/**
 * Basic monitor data.
 */
export interface SyntheticMonitorSummaryDto {
    /**
     * If true, the monitor is enabled.
     */
    enabled?: boolean;
    /**
     * The entity id of the monitor.
     */
    entityId: string;
    /**
     * The name of the monitor.
     */
    name: string;
    type: 'BROWSER' | 'HTTP' | 'MULTI_PROTOCOL' | 'THIRD_PARTY';
}
